class PricingStrategyFactory {
    static PricingStrategy forMovieType(MovieType movieType) {
        switch (movieType) {
            case REGULAR:     return new RegularPricingStrategy();
            case NEW_RELEASE: return new NewReleasePricingStrategy();
            case CHILDRENS:   return new ChildrensPricingStrategy();
        }
        throw new IllegalArgumentException("No pricing strategy for movie type: " + movieType);
    }
}
